"use client";

import { FormEvent, useEffect, useMemo, useState } from "react";

const API_BASE =
  process.env.NEXT_PUBLIC_API_BASE_URL || "http://localhost:4001";

type QRightObject = {
  id: string;
  title: string;
  description: string;
  kind: string;
  contentHash: string;
  ownerName: string | null;
  ownerEmail: string | null;
  signature: string | null;
  createdAt: string;
};

function shortHash(hash: string) {
  if (!hash) return "";
  if (hash.length <= 16) return hash;
  return `${hash.slice(0, 10)}…${hash.slice(-6)}`;
}

export default function QRightPage() {
  const [items, setItems] = useState<QRightObject[]>([]);
  const [loading, setLoading] = useState(true);
  const [err, setErr] = useState<string | null>(null);
  const [signingId, setSigningId] = useState<string | null>(null);
  const [mode, setMode] = useState<"all" | "signed">("all");
  const [hasToken, setHasToken] = useState(false);
  const [copyBusyId, setCopyBusyId] = useState<string | null>(null);

  // Form state
  const [title, setTitle] = useState("");
  const [kind, setKind] = useState("idea");
  const [description, setDescription] = useState("");
  const [ownerName, setOwnerName] = useState("");
  const [ownerEmail, setOwnerEmail] = useState("");

  const canSubmit = useMemo(() => {
    // ownerName/ownerEmail опциональны
    return Boolean(title.trim() && description.trim());
  }, [title, description]);

  const load = async (m: "all" | "signed") => {
    try {
      setLoading(true);
      setErr(null);

      let authHeader: Record<string, string> | undefined = undefined;
      try {
        const t = localStorage.getItem("aevion_token") || "";
        if (t) authHeader = { Authorization: `Bearer ${t}` };
      } catch {
        // ignore
      }

      const endpoint =
        m === "signed"
          ? `${API_BASE}/api/qright/objects/signed`
          : `${API_BASE}/api/qright/objects`;

      const res = await fetch(endpoint, { headers: authHeader });
      const data = await res.json().catch(() => null);
      if (!res.ok) {
        throw new Error(
          data?.error || "Ошибка загрузки реестра QRight"
        );
      }

      setItems((data?.items || []) as QRightObject[]);
    } catch (e) {
      setErr((e as Error).message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    try {
      const params = new URLSearchParams(window.location.search);
      const m = params.get("mode");
      if (m === "signed") setMode("signed");
      if (m === "all") setMode("all");
    } catch {
      // ignore
    }
  }, []);

  useEffect(() => {
    try {
      const t = localStorage.getItem("aevion_token") || "";
      setHasToken(Boolean(t));
    } catch {
      setHasToken(false);
    }
  }, []);

  useEffect(() => {
    load(mode);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [mode]);

  const create = async (e: FormEvent) => {
    e.preventDefault();

    if (!title.trim() || !description.trim()) {
      setErr("Title и description обязательны");
      return;
    }

    setErr(null);

    let authHeader: Record<string, string> | undefined = undefined;
    try {
      const t = localStorage.getItem("aevion_token") || "";
      if (t) authHeader = { Authorization: `Bearer ${t}` };
    } catch {
      // ignore
    }

    const res = await fetch(`${API_BASE}/api/qright/objects`, {
      method: "POST",
      headers: { "Content-Type": "application/json", ...authHeader },
      body: JSON.stringify({
        title,
        kind,
        description,
        ownerName: ownerName.trim() ? ownerName : null,
        ownerEmail: ownerEmail.trim() ? ownerEmail : null,
      }),
    });

    const data = await res.json().catch(() => null);
    if (!res.ok) {
      if (res.status === 409) {
        setErr(data?.message || "Object already registered");
        return;
      }
      setErr(data?.error || "Ошибка создания объекта QRight");
      return;
    }

    // Clear required fields after successful create.
    setTitle("");
    setDescription("");
    setKind("idea");

    await load(mode);
  };

  const signObject = async (id: string) => {
    setErr(null);
    setSigningId(id);
    try {
      let token = "";
      try {
        token = localStorage.getItem("aevion_token") || "";
      } catch {
        // ignore
      }
      if (!token) {
        setErr("Нужно войти (Auth), чтобы подписать объект");
        return;
      }

      let authHeader: Record<string, string> | undefined = undefined;
      try {
        authHeader = { Authorization: `Bearer ${token}` };
      } catch {
        // ignore
      }

      const res = await fetch(`${API_BASE}/api/qright/objects/${id}/sign`, {
        method: "POST",
        headers: { "Content-Type": "application/json", ...authHeader },
      });

      const data = await res.json().catch(() => null);
      if (!res.ok) {
        setErr(data?.error || "Ошибка подписания");
        return;
      }

      await load(mode);
    } catch (e: any) {
      setErr(e?.message || "Ошибка подписания");
    } finally {
      setSigningId(null);
    }
  };

  const copyText = async (busyKey: string, text: string) => {
    if (!text) return;
    setCopyBusyId(busyKey);
    try {
      await navigator.clipboard.writeText(text);
    } catch {
      // Игнорируем, если clipboard недоступен.
    } finally {
      setCopyBusyId(null);
    }
  };

  return (
    <main style={{ padding: 24, maxWidth: 980 }}>
      <div style={{ display: "flex", justifyContent: "space-between" }}>
        <div>
          <h1 style={{ fontSize: 26, marginBottom: 6 }}>QRight</h1>
          <p style={{ color: "#666", marginTop: 0 }}>
            Электронная регистрация (MVP): создание объектов и реестр.
          </p>
        </div>
        <div style={{ display: "flex", gap: 12, alignItems: "center" }}>
          <a href="/" style={{ color: "#0a5" }}>
            Главная
          </a>
          <a href="/qtrade" style={{ color: "#0a5" }}>
            QTrade
          </a>
          <a href="/qsign" style={{ color: "#0a5" }}>
            QSign
          </a>
        </div>
      </div>

      {err && (
        <div style={{ margin: "12px 0", color: "crimson" }}>
          Ошибка: {err}
        </div>
      )}

      {!hasToken ? (
        <div
          style={{
            marginTop: 12,
            padding: 12,
            borderRadius: 10,
            border: "1px solid #ffddb3",
            background: "#fff7e6",
            color: "#7a4a00",
          }}
        >
          Чтобы видеть только ваши объекты и подписывать как владелец —{" "}
          <a href="/auth" style={{ color: "#0a5", textDecoration: "none" }}>
            войдите в Auth
          </a>
          .
        </div>
      ) : null}

      <section
        style={{
          border: "1px solid #ddd",
          borderRadius: 10,
          padding: 14,
          marginTop: 18,
        }}
      >
        <h2 style={{ fontSize: 18, marginBottom: 10 }}>Создать объект</h2>

        <form onSubmit={create} style={{ display: "grid", gap: 10 }}>
          <input
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            placeholder="Title (обязательное)"
            style={{
              padding: 10,
              borderRadius: 8,
              border: "1px solid #ccc",
            }}
          />

          <input
            value={kind}
            onChange={(e) => setKind(e.target.value)}
            placeholder="Kind (например idea / invention)"
            style={{
              padding: 10,
              borderRadius: 8,
              border: "1px solid #ccc",
            }}
          />

          <textarea
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            placeholder="Description (обязательное)"
            rows={6}
            style={{
              padding: 10,
              borderRadius: 8,
              border: "1px solid #ccc",
              fontFamily: "monospace",
            }}
          />

          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
            <input
              value={ownerName}
              onChange={(e) => setOwnerName(e.target.value)}
              placeholder="Owner name (опционально)"
              style={{
                padding: 10,
                borderRadius: 8,
                border: "1px solid #ccc",
              }}
            />
            <input
              value={ownerEmail}
              onChange={(e) => setOwnerEmail(e.target.value)}
              placeholder="Owner email (опционально)"
              style={{
                padding: 10,
                borderRadius: 8,
                border: "1px solid #ccc",
              }}
            />
          </div>

          <button
            type="submit"
            disabled={!canSubmit}
            style={{
              padding: 10,
              borderRadius: 8,
              border: "1px solid #111",
              background: canSubmit ? "#111" : "#888",
              color: "#fff",
              width: 220,
            }}
          >
            Зарегистрировать
          </button>
        </form>
      </section>

      <section style={{ marginTop: 22 }}>
        <div style={{ display: "flex", justifyContent: "space-between" }}>
          <h2 style={{ fontSize: 18, marginBottom: 10 }}>
            Реестр объектов ({items.length})
          </h2>
          <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
            <button
              type="button"
              onClick={() => setMode("all")}
              style={{
                padding: "8px 12px",
                borderRadius: 8,
                border: "1px solid #ccc",
                background: mode === "all" ? "#111" : "#fff",
                color: mode === "all" ? "#fff" : "#111",
                cursor: "pointer",
              }}
            >
              Все
            </button>
            <button
              type="button"
              onClick={() => setMode("signed")}
              style={{
                padding: "8px 12px",
                borderRadius: 8,
                border: "1px solid #ccc",
                background: mode === "signed" ? "#0a5" : "#fff",
                color: mode === "signed" ? "#fff" : "#0a5",
                cursor: "pointer",
              }}
            >
              Подписанные
            </button>
          </div>
        </div>

        {loading ? (
          <div>Загрузка…</div>
        ) : items.length === 0 ? (
          <div style={{ color: "#666" }}>
            Пока нет зарегистрированных объектов.
          </div>
        ) : (
          <div style={{ display: "grid", gap: 12 }}>
            {items.map((it) => (
              <div
                key={it.id}
                style={{
                  border: "1px solid #ddd",
                  borderRadius: 10,
                  padding: 14,
                }}
              >
                <div style={{ display: "flex", justifyContent: "space-between" }}>
                  <div style={{ fontWeight: 700, fontSize: 16 }}>
                    {it.title}
                  </div>
                  <div style={{ fontSize: 12, color: "#666" }}>
                    {new Date(it.createdAt).toLocaleString()}
                  </div>
                </div>

                <div style={{ marginTop: 6, color: "#666" }}>
                  <div>
                    kind: <b>{it.kind}</b>
                  </div>
                  <div>
                    ownerName: <b>{it.ownerName ?? "—"}</b>
                  </div>
                  <div>
                    ownerEmail: <b>{it.ownerEmail ?? "—"}</b>
                  </div>
                </div>

                <div style={{ marginTop: 10, fontFamily: "monospace", fontSize: 13 }}>
                  {it.description}
                </div>

                <div
                  style={{
                    marginTop: 10,
                    paddingTop: 10,
                    borderTop: "1px solid #eee",
                    display: "grid",
                    gap: 6,
                    fontSize: 12,
                    color: "#666",
                  }}
                >
                  <div>
                    contentHash:{" "}
                    <span title={it.contentHash}>{shortHash(it.contentHash)}</span>
                  </div>
                  <div style={{ marginTop: 6 }}>
                    <button
                      type="button"
                      onClick={() =>
                        copyText(`${it.id}:hash`, it.contentHash)
                      }
                      disabled={copyBusyId === `${it.id}:hash`}
                      style={{
                        padding: "6px 10px",
                        borderRadius: 8,
                        border: "1px solid #ccc",
                        background: "#fff",
                        cursor: "pointer",
                        fontSize: 12,
                      }}
                    >
                      {copyBusyId === `${it.id}:hash`
                        ? "Копируем..."
                        : "Копировать contentHash"}
                    </button>
                  </div>
                  <div>
                    signature:{" "}
                    {it.signature ? (
                      <span title={it.signature}>
                        <b>{shortHash(it.signature)}</b>
                      </span>
                    ) : (
                      <b>—</b>
                    )}
                  </div>
                  {it.signature ? (
                    <div style={{ marginTop: 6 }}>
                      <button
                        type="button"
                        onClick={() =>
                          copyText(`${it.id}:sig`, it.signature || "")
                        }
                        disabled={copyBusyId === `${it.id}:sig`}
                        style={{
                          padding: "6px 10px",
                          borderRadius: 8,
                          border: "1px solid #ccc",
                          background: "#fff",
                          cursor: "pointer",
                          fontSize: 12,
                        }}
                      >
                        {copyBusyId === `${it.id}:sig`
                          ? "Копируем..."
                          : "Копировать signature"}
                      </button>
                    </div>
                  ) : null}
                  <div style={{ fontSize: 11 }}>
                    id: <span>{it.id}</span>
                  </div>
                </div>

                <div style={{ marginTop: 10 }}>
                  <button
                    type="button"
                    onClick={() => signObject(it.id)}
                    disabled={Boolean(it.signature) || signingId === it.id}
                    style={{
                      padding: 10,
                      borderRadius: 8,
                      border: Boolean(it.signature)
                        ? "1px solid #ccc"
                        : "1px solid #0a5",
                      background: Boolean(it.signature) ? "#eee" : "#0a5",
                      color: Boolean(it.signature) ? "#666" : "#fff",
                      width: 240,
                    }}
                  >
                    {Boolean(it.signature)
                      ? "Подписано"
                      : signingId === it.id
                        ? "Подписываем..."
                        : "Подписать"}
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </section>
    </main>
  );
}

